import { ChevronLeft, RefreshCw, Square, Trash2 } from 'lucide-react';
import { useCallback, useEffect, useMemo, useState } from 'react';
import {
  getCodexRuns,
  getTaskDashboard,
  killAllCodexRuns,
  killConversationSession,
  rollbackTaskRun
} from '../lib/api';
import BottomNav from './BottomNav';
import type { CodexBackgroundRun, Conversation, Screen, TaskRunDashboardItem, TerminalEntry } from '../lib/types';

function formatTime(value: string) {
  const date = value ? new Date(value) : null;
  if (!date || Number.isNaN(date.getTime())) return '--:--:--';
  return date.toLocaleTimeString('es-ES', {
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
  });
}

function formatElapsed(startedAt: string) {
  const timestamp = Date.parse(String(startedAt || ''));
  if (!Number.isFinite(timestamp)) return '--';
  const totalSeconds = Math.max(0, Math.floor((Date.now() - timestamp) / 1000));
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
}

function toTimestamp(value: string): number {
  const parsed = Date.parse(String(value || ''));
  return Number.isFinite(parsed) ? parsed : 0;
}

function normalizeConversationId(value: unknown): number | null {
  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed <= 0) return null;
  return parsed;
}

interface TerminalGroup {
  key: string;
  conversationId: number | null;
  title: string;
  entries: TerminalEntry[];
  latestAt: number;
}

