    setRunsError('');
    try {
      const nextRuns = await getCodexRuns();
      setRuns(nextRuns);
    } catch (error) {
      setRunsError(error instanceof Error ? error.message : 'No se pudieron cargar los procesos activos');
    } finally {
      if (!silent) {
        setRunsLoading(false);
      }
    }
  }, []);

